import type { PermissionResponse, HookResponse } from "@agnt/shared";
import type { AgentEvent, AgentOptions } from "./types.js";

export abstract class BaseAgent {
  abstract readonly type: string;

  protected activeSessions = new Map<string, AbortController>();

  /**
   * Execute a prompt and yield agent events.
   * The returned iterator streams events for a single turn.
   */
  abstract execute(
    prompt: string,
    options: AgentOptions,
  ): AsyncIterableIterator<AgentEvent>;

  /**
   * Cancel a running session by session ID.
   */
  abstract cancel(sessionId: string): Promise<void>;

  /**
   * Terminate all active sessions. Called during graceful shutdown.
   */
  abstract terminateAll(): void;

  /**
   * Resolve a pending MCP question with the user's answer.
   * Override in subclasses that support MCP question/answer flow.
   * Returns true if the answer was resolved, false otherwise.
   */
  resolveAnswer(_sessionId: string, _questionId: string, _answers: string[]): boolean {
    return false;
  }

  /**
   * Resolve a pending permission request from the canUseTool bridge.
   * Override in subclasses that support the permission request flow.
   * Returns true if the request was resolved, false otherwise.
   */
  resolvePermission(_requestId: string, _response: PermissionResponse): boolean {
    return false;
  }

  /**
   * Resolve a pending hook decision request.
   * Override in subclasses that support the hook bridge.
   * Returns true if the request was resolved, false otherwise.
   */
  resolveHook(_requestId: string, _response: HookResponse): boolean {
    return false;
  }
}

