import type { AgentExecutePayload, SessionChannelEvent, AgentOutput, McpAnswer, PermissionRequest, PermissionResponse, HookRequest, HookResponse } from "@agnt/shared";
import type { Logger } from "@agnt/logger";
import type { SessionEventSender } from "../types.js";
import type { AgentRegistry } from "./registry.js";
import type { McpQuestionPayload } from "../mcp/internal-server.js";

/**
 * Orchestrates WebSocket command dispatch to agent execution and event streaming.
 *
 * - handleExecute: fire-and-forget async that runs the agent and streams events via WS
 * - handleCancel: interrupts a running session
 * - handleMcpAnswer: resolves a pending AskUserQuestion with the user's answer
 * - shutdown: terminates all sessions for graceful exit
 */
export class AgentController {
  constructor(
    private readonly registry: AgentRegistry,
    private readonly sender: SessionEventSender,
    private readonly logger: Logger,
    private readonly agentType: string = "claude-code",
  ) {}

  handleExecute(payload: AgentExecutePayload): void {
    // Fire-and-forget — the execution streams events back via WebSocket
    this.executeAsync(payload).catch((err) => {
      this.logger.error({ err, sessionId: payload.sessionId }, "Unhandled execute error");
    });
  }

  async handleCancel(sessionId: string): Promise<void> {
    const agent = this.registry.get(this.agentType);
    if (!agent) {
      this.logger.warn({ sessionId }, "No agent registered for cancel");
      return;
    }

    try {
      await agent.cancel(sessionId);
      this.sendStatus(sessionId, "idle");
      this.logger.info({ sessionId }, "Agent cancelled");
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      this.logger.error({ err, sessionId }, "Cancel failed");
      this.sendStatus(sessionId, "failed", errorMessage);
    }
  }

  handleMcpAnswer(data: McpAnswer): void {
    const agent = this.registry.get(this.agentType);
    if (!agent) {
      this.logger.warn({ sessionId: data.sessionId }, "No agent registered for MCP answer");
      return;
    }

    const resolved = agent.resolveAnswer(data.sessionId, data.questionId, data.answers);
    this.logger.info(
      { sessionId: data.sessionId, questionId: data.questionId, resolved },
      "MCP answer handled",
    );
  }

  handlePermissionResponse(data: PermissionResponse): void {
    const agent = this.registry.get(this.agentType);
    if (!agent) {
      this.logger.warn({ sessionId: data.sessionId }, "No agent registered for permission response");
      return;
    }

    const resolved = agent.resolvePermission(data.requestId, data);
    this.logger.info(
      { sessionId: data.sessionId, requestId: data.requestId, resolved },
      "Permission response handled",
    );
  }

  /**
   * Called by the canUseTool bridge when a permission request is emitted.
   * Sends the request as a sidecar event to the backend.
   */
  emitPermissionRequest(payload: PermissionRequest): void {
    this.sender.sendToSession(payload.sessionId, {
      event: "permission:request",
      data: payload,
    });

    this.logger.info(
      { sessionId: payload.sessionId, requestId: payload.requestId, toolName: payload.toolName },
      "Permission request emitted to backend",
    );
  }

  /**
   * Called by the hook bridge when a hook event fires.
   * Sends the hook request as a sidecar event to the backend.
   */
  emitHookEvent(payload: HookRequest): void {
    this.sender.sendToSession(payload.sessionId, {
      event: "hook:request",
      data: payload,
    });

    this.logger.info(
      { sessionId: payload.sessionId, requestId: payload.requestId, hookEvent: payload.hookEventName, needsResponse: payload.needsResponse },
      "Hook event emitted to backend",
    );
  }

  handleHookResponse(data: HookResponse): void {
    const agent = this.registry.get(this.agentType);
    if (!agent) {
      this.logger.warn({ sessionId: data.sessionId }, "No agent registered for hook response");
      return;
    }

    const resolved = agent.resolveHook(data.requestId, data);
    this.logger.info(
      { sessionId: data.sessionId, requestId: data.requestId, resolved },
      "Hook response handled",
    );
  }

  shutdown(): void {
    this.registry.terminateAll();
    this.logger.info("All agent sessions terminated");
  }

  private async executeAsync(payload: AgentExecutePayload): Promise<void> {
    const { sessionId, prompt, options } = payload;

    const agent = this.registry.get(this.agentType);
    if (!agent) {
      this.logger.error("No agent registered for execution");
      this.sendStatus(sessionId, "failed", "No agent registered for execution");
      return;
    }

    this.sendStatus(sessionId, "running");

    try {
      const iterator = agent.execute(prompt, {
        sessionId,
        cwd: options.cwd,
        model: options.model,
        permissionMode: options.permissionMode,
        maxTurns: options.maxTurns,
        apiKey: options.apiKey,
        resume: options.resume,
        resumeAgentSessionAt: options.resumeAgentSessionAt,
        appendSystemPrompt: options.appendSystemPrompt,
        mcpServers: options.mcpServers,
        baseUrl: options.baseUrl,
        maxThinkingTokens: options.maxThinkingTokens,
        includePartialMessages: options.includePartialMessages,
        shouldResetGenerator: options.shouldResetGenerator,
        hooks: options.hooks,
      });

      for await (const event of iterator) {
        const output: AgentOutput = {
          sessionId,
          timestamp: new Date().toISOString(),
          data: event,
        };

        this.sender.sendToSession(sessionId, {
          event: "agent:output",
          data: output,
        });
      }

      this.sendStatus(sessionId, "completed");
      this.logger.info({ sessionId }, "Agent execution completed");
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      this.logger.error(
        {
          sessionId,
          errorType: typeof err,
          errorName: err instanceof Error ? err.name : undefined,
          errorMessage,
          errorConstructor: err?.constructor?.name,
          errorStack: err instanceof Error ? err.stack?.split("\n").slice(0, 5).join("\n") : undefined,
        },
        "Agent execution failed",
      );
      this.sendStatus(sessionId, "failed", errorMessage);
    }
  }

  /**
   * Called by the MCP internal server when AskUserQuestion is invoked.
   * Emits the question as a sidecar event to the backend.
   */
  emitMcpQuestion(payload: McpQuestionPayload): void {
    this.sender.sendToSession(payload.sessionId, {
      event: "mcp:question",
      data: payload,
    });

    this.logger.info(
      { sessionId: payload.sessionId, questionId: payload.questionId },
      "MCP question emitted to backend",
    );
  }

  private sendStatus(sessionId: string, status: "idle" | "running" | "completed" | "failed", error?: string): void {
    this.sender.sendToSession(sessionId, {
      event: "agent:status",
      data: { sessionId, status, ...(error ? { error } : {}) },
    });
  }
}

