import { BaseAgent } from "../base-agent.js";
import type { AgentEvent, AgentOptions, OnQuestionAsked, OnPermissionRequest, OnHookEvent } from "../types.js";
import { ClaudeSessionManager } from "./session-manager.js";
import { SessionTerminatedError, type SessionConfig } from "./generator-session.js";
import { AgentExecutionError } from "../../utils/errors.js";
import { apiKeyStore } from "../../stores/api-key-store.js";
import type { Logger } from "@agnt/logger";
import type { PermissionResponse, HookResponse } from "@agnt/shared";

/** Placeholder key that satisfies Claude Code SDK validation but never reaches Anthropic. */
const PROXY_PLACEHOLDER = "sk-proxy-managed";

export class ClaudeCodeAgent extends BaseAgent {
  readonly type = "claude-code";

  private readonly sessionManager: ClaudeSessionManager;
  private readonly logger: Logger;
  private readonly defaultApiKey?: string;
  private readonly sidecarPort: number;
  private readonly cancelling = new Set<string>();

  constructor(
    logger: Logger,
    defaultApiKey?: string,
    sidecarPort?: number,
    onQuestionAsked?: OnQuestionAsked,
    onPermissionRequest?: OnPermissionRequest,
    onHookEvent?: OnHookEvent,
  ) {
    super();
    this.logger = logger;
    this.defaultApiKey = defaultApiKey;
    this.sidecarPort = sidecarPort ?? 3001;
    this.sessionManager = new ClaudeSessionManager(logger, onQuestionAsked, onPermissionRequest, onHookEvent);
  }

  async *execute(
    prompt: string,
    options: AgentOptions,
  ): AsyncIterableIterator<AgentEvent> {
    const sessionKey = options.sessionId;

    this.logger.info(
      { sessionKey, cwd: options.cwd, model: options.model },
      "Starting Claude Code execution",
    );

    const realApiKey = options.apiKey || this.defaultApiKey || process.env.ANTHROPIC_API_KEY;
    if (!realApiKey) {
      throw new AgentExecutionError("ANTHROPIC_API_KEY not provided", {
        sessionId: sessionKey,
      });
    }

    // Store real key in memory for the proxy (updated on every execution).
    // The proxy swaps the placeholder for the real key before forwarding to Anthropic.
    const upstreamBaseUrl = options.baseUrl || process.env.ANTHROPIC_BASE_URL;
    apiKeyStore.set(sessionKey, realApiKey, upstreamBaseUrl);

    // Build proxy URL — agent subprocess calls this instead of Anthropic directly
    const proxyBaseUrl = `http://localhost:${this.sidecarPort}/proxy/anthropic/${sessionKey}`;

    const sessionConfig: SessionConfig = {
      cwd: options.cwd,
      apiKey: PROXY_PLACEHOLDER,
      baseUrl: proxyBaseUrl,
      model: options.model,
      maxTurns: options.maxTurns,
      permissionMode: options.permissionMode,
      appendSystemPrompt: options.appendSystemPrompt,
      resume: options.resume,
      resumeAgentSessionAt: options.resumeAgentSessionAt,
      mcpServers: options.mcpServers,
      maxThinkingTokens: options.maxThinkingTokens,
      includePartialMessages: options.includePartialMessages,
      hooks: options.hooks,
    };

    // Force reset if requested
    if (options.shouldResetGenerator) {
      this.logger.info({ sessionKey }, "Resetting generator session (explicit request)");
      await this.sessionManager.terminate(sessionKey);
    }

    // Track abort controller for this execution
    const abortController = new AbortController();
    this.activeSessions.set(sessionKey, abortController);

    try {
      const session = await this.sessionManager.getOrCreate(sessionKey, sessionConfig);
      const tap = await session.sendMessage(prompt);

      // Wire abort signal to detach tap (not kill session — allows reuse)
      const onAbort = () => tap.detach();
      if (abortController.signal.aborted) {
        onAbort();
      } else {
        abortController.signal.addEventListener("abort", onAbort);
      }

      try {
        for await (const event of tap.events) {
          yield event;
        }
      } finally {
        abortController.signal.removeEventListener("abort", onAbort);
        tap.detach();
      }

      this.logger.info({ sessionKey }, "Claude Code execution completed");
    } catch (error) {
      this.logger.error(
        {
          sessionKey,
          errorType: typeof error,
          errorName: error instanceof Error ? error.name : undefined,
          errorMessage: error instanceof Error ? error.message : String(error),
          errorConstructor: error?.constructor?.name,
          errorStack: error instanceof Error ? error.stack?.split("\n").slice(0, 5).join("\n") : undefined,
        },
        "Claude Code execution error",
      );

      if (
        error instanceof SessionTerminatedError ||
        (error instanceof Error && error.name === "AbortError")
      ) {
        yield {
          type: "system",
          subtype: "error",
          error: error instanceof Error ? error.message : String(error),
          aborted: true,
        };
        return;
      }

      // Wrap unknown errors in AgentExecutionError for consistent handling
      throw error instanceof AgentExecutionError
        ? error
        : new AgentExecutionError(
            error instanceof Error ? error.message : String(error),
            { sessionId: sessionKey },
          );
    } finally {
      this.activeSessions.delete(sessionKey);
    }
  }

  /**
   * Resolve a pending MCP question answer.
   * Routes to the GeneratorSession that owns the given sessionId.
   */
  resolveAnswer(sessionId: string, questionId: string, answers: string[]): boolean {
    // Try direct key lookup first
    const session = this.sessionManager.get(sessionId);
    if (session) {
      return session.resolveAnswer(questionId, answers);
    }

    // Fall back to SDK session ID lookup
    const bySDK = this.sessionManager.findBySessionId(sessionId);
    if (bySDK) {
      return bySDK.resolveAnswer(questionId, answers);
    }

    this.logger.warn({ sessionId, questionId }, "No session found to resolve MCP answer");
    return false;
  }

  /**
   * Resolve a pending permission request from the canUseTool bridge.
   * Routes to the GeneratorSession that owns the given sessionId.
   */
  resolvePermission(requestId: string, response: PermissionResponse): boolean {
    // Try direct key lookup first
    const session = this.sessionManager.get(response.sessionId);
    if (session) {
      return session.resolvePermission(requestId, response);
    }

    // Fall back to SDK session ID lookup
    const bySDK = this.sessionManager.findBySessionId(response.sessionId);
    if (bySDK) {
      return bySDK.resolvePermission(requestId, response);
    }

    this.logger.warn({ sessionId: response.sessionId, requestId }, "No session found to resolve permission");
    return false;
  }

  /**
   * Resolve a pending hook decision request.
   * Routes to the GeneratorSession that owns the given sessionId.
   */
  resolveHook(requestId: string, response: HookResponse): boolean {
    // Try direct key lookup first
    const session = this.sessionManager.get(response.sessionId);
    if (session) {
      return session.resolveHook(requestId, response);
    }

    // Fall back to SDK session ID lookup
    const bySDK = this.sessionManager.findBySessionId(response.sessionId);
    if (bySDK) {
      return bySDK.resolveHook(requestId, response);
    }

    this.logger.warn({ sessionId: response.sessionId, requestId }, "No session found to resolve hook");
    return false;
  }

  async cancel(sessionId: string): Promise<void> {
    if (this.cancelling.has(sessionId)) {
      this.logger.info({ sessionId }, "Cancel already in progress, skipping duplicate");
      return;
    }

    this.cancelling.add(sessionId);
    try {
      this.logger.info({ sessionId }, "Cancelling Claude Code session");

      // Try to abort via active session tracking
      const abortController = this.activeSessions.get(sessionId);
      if (abortController) {
        abortController.abort();
        this.activeSessions.delete(sessionId);
      }

      // Deduplicated session lookup: try direct key first, then SDK session ID fallback
      const session = this.sessionManager.get(sessionId) ?? this.sessionManager.findBySessionId(sessionId);
      if (session) {
        await session.interruptTurn();
      }
    } finally {
      this.cancelling.delete(sessionId);
    }
  }

  terminateAll(): void {
    // Abort all active executions
    for (const [, controller] of this.activeSessions) {
      controller.abort();
    }
    this.activeSessions.clear();

    this.sessionManager.terminateAll().catch((err) => {
      this.logger.error({ err }, "Error terminating all sessions");
    });
  }
}

