import { GeneratorSession, type SessionConfig } from "./generator-session.js";
import type { OnQuestionAsked, OnPermissionRequest, OnHookEvent } from "../types.js";
import { apiKeyStore } from "../../stores/api-key-store.js";
import type { Logger } from "@agnt/logger";

/**
 * Manages the lifecycle of GeneratorSession instances.
 *
 * One session per key (typically the sessionId from the backend).
 * Sessions are reused across requests until config changes, explicit
 * termination, or idle timeout.
 */
export class ClaudeSessionManager {
  private readonly sessions = new Map<string, GeneratorSession>();
  private readonly logger: Logger;
  private readonly onQuestionAsked?: OnQuestionAsked;
  private readonly onPermissionRequest?: OnPermissionRequest;
  private readonly onHookEvent?: OnHookEvent;

  constructor(logger: Logger, onQuestionAsked?: OnQuestionAsked, onPermissionRequest?: OnPermissionRequest, onHookEvent?: OnHookEvent) {
    this.logger = logger;
    this.onQuestionAsked = onQuestionAsked;
    this.onPermissionRequest = onPermissionRequest;
    this.onHookEvent = onHookEvent;
  }

  async getOrCreate(key: string, config: SessionConfig): Promise<GeneratorSession> {
    const existing = this.sessions.get(key);

    if (existing && existing.currentState !== "terminated") {
      if (this.configChanged(existing.currentConfig, config)) {
        this.logger.info({ key }, "Config changed, resetting session");
        await existing.terminate();
      } else {
        return existing;
      }
    }

    const session = new GeneratorSession(
      key,
      config,
      this.logger,
      () => {
        this.sessions.delete(key);
        apiKeyStore.delete(key);
      },
      this.onQuestionAsked,
      this.onPermissionRequest,
      this.onHookEvent,
    );
    this.sessions.set(key, session);
    await session.start();
    return session;
  }

  get(key: string): GeneratorSession | undefined {
    const session = this.sessions.get(key);
    return session?.currentState !== "terminated" ? session : undefined;
  }

  findBySessionId(sdkSessionId: string): GeneratorSession | undefined {
    for (const session of this.sessions.values()) {
      if (
        session.currentSessionId === sdkSessionId &&
        session.currentState !== "terminated"
      ) {
        return session;
      }
    }
    return undefined;
  }

  async terminate(key: string): Promise<void> {
    await this.sessions.get(key)?.terminate();
  }

  async terminateAll(): Promise<void> {
    await Promise.all(
      [...this.sessions.values()].map((s) => s.terminate()),
    );
  }

  private configChanged(
    current: Readonly<SessionConfig>,
    incoming: SessionConfig,
  ): boolean {
    return (
      current.cwd !== incoming.cwd ||
      current.model !== incoming.model ||
      current.apiKey !== incoming.apiKey ||
      current.baseUrl !== incoming.baseUrl ||
      current.appendSystemPrompt !== incoming.appendSystemPrompt ||
      current.permissionMode !== incoming.permissionMode ||
      !mcpServersEqual(current.mcpServers, incoming.mcpServers) ||
      !hooksEqual(current.hooks, incoming.hooks)
    );
  }
}

// ── MCP Config Comparison ──

/**
 * Order-independent deep equality for MCP server config maps.
 * Uses sorted-key JSON serialization so { a: 1, b: 2 } === { b: 2, a: 1 }.
 */
function mcpServersEqual(
  a: Record<string, unknown> | undefined,
  b: Record<string, unknown> | undefined,
): boolean {
  if (a === b) return true;
  if (!a && !b) return true;
  if (!a || !b) return false;
  return stableStringify(a) === stableStringify(b);
}

/** Recursively serialize with sorted keys for deterministic comparison. */
function stableStringify(value: unknown): string {
  if (value === null || value === undefined) return String(value);
  if (typeof value !== "object") return JSON.stringify(value);
  if (Array.isArray(value)) {
    return "[" + value.map(stableStringify).join(",") + "]";
  }
  const obj = value as Record<string, unknown>;
  const keys = Object.keys(obj).sort();
  const entries = keys.map((k) => JSON.stringify(k) + ":" + stableStringify(obj[k]));
  return "{" + entries.join(",") + "}";
}

/**
 * Order-independent equality for hook subscription arrays.
 * Both undefined and [] are treated as "no hooks".
 */
function hooksEqual(a: string[] | undefined, b: string[] | undefined): boolean {
  const aSet = a && a.length > 0 ? a : [];
  const bSet = b && b.length > 0 ? b : [];
  if (aSet.length !== bSet.length) return false;
  const sorted1 = [...aSet].sort();
  const sorted2 = [...bSet].sort();
  return sorted1.every((v, i) => v === sorted2[i]);
}

export { mcpServersEqual, stableStringify, hooksEqual };

