import {
  query,
  type Query as CCQuery,
  type SDKUserMessage,
  type Options as CCOptions,
  type McpServerConfig as SDKMcpServerConfig,
} from "@anthropic-ai/claude-agent-sdk";
import { McpServerConfigSchema, generateUUID7, type PermissionResponse, type HookResponse } from "@agnt/shared";
import { AsyncQueue } from "../../utils/async-queue.js";
import type { AgentEvent, OnQuestionAsked, OnPermissionRequest, OnHookEvent } from "../types.js";
import { buildHooks } from "./hook-bridge.js";
import type { Logger } from "@agnt/logger";
import { PendingQuestionsStore } from "../../mcp/pending-questions.js";
import { PendingRequestStore } from "../../mcp/pending-requests.js";
import { createInternalMcpServer } from "../../mcp/internal-server.js";
import { INTERNAL_MCP_PREFIX, INTERNAL_MCP_SERVER_NAME } from "../../mcp/constants.js";

// ── Types ──

export type SessionState = "starting" | "idle" | "busy" | "terminated";

export interface SessionConfig {
  cwd: string;
  apiKey: string;
  model?: string;
  maxTurns?: number;
  permissionMode?: CCOptions["permissionMode"];
  appendSystemPrompt?: string;
  resume?: boolean;
  resumeAgentSessionAt?: string;
  idleTimeoutMs?: number;
  /** External MCP server configs (named map, e.g. { "my-server": { type: "stdio", ... } }) */
  mcpServers?: Record<string, unknown>;
  baseUrl?: string;
  maxThinkingTokens?: number;
  includePartialMessages?: boolean;
  /** Hook events to subscribe to. Only listed hooks are registered. */
  hooks?: string[];
}

/** Events that flow through per-request taps. */
type TapEvent = AgentEvent;

/** Per-request handle to consume session events. */
export interface EventTap {
  readonly events: AsyncIterableIterator<TapEvent>;
  detach(): void;
}

export class SessionTerminatedError extends Error {
  constructor(message = "Session is terminated") {
    super(message);
    this.name = "SessionTerminatedError";
  }
}

// ── GeneratorSession ──

/**
 * Wraps a long-lived Claude Code SDK `query()` call.
 *
 * The SDK's prompt input is an AsyncQueue that stays open between requests.
 * New user messages are pushed into the queue, the SDK processes them as turns,
 * and events are broadcast to per-request EventTaps.
 *
 * Lifecycle: starting -> idle <-> busy -> terminated
 */
export class GeneratorSession {
  private state: SessionState = "starting";
  private readonly config: SessionConfig;

  // SDK
  private readonly promptQueue = new AsyncQueue<SDKUserMessage>();
  private queryInstance: CCQuery | null = null;
  private sdkSessionId: string | null = null;

  // Event routing: one tap per active request
  private readonly taps = new Set<AsyncQueue<TapEvent>>();

  // Concurrency: callers waiting for idle state (FIFO)
  private readonly idleWaiters: (() => void)[] = [];

  // Lifecycle
  private idleTimer: ReturnType<typeof setTimeout> | null = null;
  private readonly idleTimeoutMs: number;
  private onTerminated?: () => void;
  private readonly logger: Logger;

  // MCP
  private readonly pendingQuestions: PendingQuestionsStore;
  private readonly onQuestionAsked?: OnQuestionAsked;

  // Permission (canUseTool bridge)
  private readonly pendingPermissions: PendingRequestStore<PermissionResponse>;
  private readonly onPermissionRequest?: OnPermissionRequest;

  // Hooks (hook bridge)
  private readonly pendingHooks: PendingRequestStore<HookResponse>;
  private readonly onHookEvent?: OnHookEvent;

  constructor(
    public readonly id: string,
    config: SessionConfig,
    logger: Logger,
    onTerminated?: () => void,
    onQuestionAsked?: OnQuestionAsked,
    onPermissionRequest?: OnPermissionRequest,
    onHookEvent?: OnHookEvent,
  ) {
    this.config = { ...config };
    this.idleTimeoutMs = config.idleTimeoutMs ?? 5 * 60_000;
    this.onTerminated = onTerminated;
    this.onQuestionAsked = onQuestionAsked;
    this.onPermissionRequest = onPermissionRequest;
    this.onHookEvent = onHookEvent;
    this.logger = logger;
    this.pendingQuestions = new PendingQuestionsStore(logger);
    this.pendingPermissions = new PendingRequestStore("permission", logger);
    this.pendingHooks = new PendingRequestStore("hook", logger);
  }

  get currentState(): SessionState {
    return this.state;
  }

  get currentSessionId(): string | null {
    return this.sdkSessionId;
  }

  get currentConfig(): Readonly<SessionConfig> {
    return this.config;
  }

  // ── MCP Answer Resolution ──

  resolveAnswer(questionId: string, answers: string[]): boolean {
    // PendingQuestionsStore keys by sessionId, not questionId.
    // The session-scoped store only tracks one pending question at a time,
    // so we resolve using the session's own ID.
    return this.pendingQuestions.resolve(this.sdkSessionId ?? this.id, answers);
  }

  // ── Permission Resolution ──

  resolvePermission(requestId: string, response: PermissionResponse): boolean {
    return this.pendingPermissions.resolve(requestId, response);
  }

  // ── Hook Resolution ──

  resolveHook(requestId: string, response: HookResponse): boolean {
    return this.pendingHooks.resolve(requestId, response);
  }

  // ── Lifecycle ──

  async start(): Promise<void> {
    if (this.state !== "starting") {
      throw new Error(`Cannot start session in state: ${this.state}`);
    }

    this.logger.info(
      { sessionId: this.id, cwd: this.config.cwd, model: this.config.model },
      "Starting generator session",
    );

    const apiKey = this.config.apiKey;
    const permissionMode = this.config.permissionMode || "bypassPermissions";
    const baseUrl = this.config.baseUrl || process.env.ANTHROPIC_BASE_URL;

    // Build MCP servers map: external (validated) + internal (always registered)
    const mcpServers: Record<string, SDKMcpServerConfig> = {};

    // External MCP servers (stdio/sse/http) passed per-session — validated with Zod
    if (this.config.mcpServers) {
      for (const [name, config] of Object.entries(this.config.mcpServers)) {
        // Reject external servers using the reserved internal prefix
        if (name.startsWith(INTERNAL_MCP_PREFIX)) {
          this.logger.warn(
            { sessionId: this.id, serverName: name },
            `Skipping external MCP server: name uses reserved prefix "${INTERNAL_MCP_PREFIX}"`,
          );
          continue;
        }

        const result = McpServerConfigSchema.safeParse(config);
        if (!result.success) {
          this.logger.warn(
            { sessionId: this.id, serverName: name, errors: result.error.issues },
            "Skipping external MCP server: invalid config",
          );
          continue;
        }

        mcpServers[name] = result.data as SDKMcpServerConfig;
      }
    }

    // Internal in-process MCP server (always registered after externals)
    const onQuestion = this.onQuestionAsked ?? ((payload) => {
      this.logger.warn(
        { sessionId: this.id, questionId: payload.questionId },
        "agnt_ask_user_question invoked but no onQuestionAsked callback is configured",
      );
    });
    const internalMcp = createInternalMcpServer(
      () => this.sdkSessionId ?? this.id,
      this.pendingQuestions,
      onQuestion,
      this.logger,
    );
    mcpServers[INTERNAL_MCP_SERVER_NAME] = internalMcp;

    // Build canUseTool callback — only when NOT bypassing permissions.
    // This routes every tool permission request through the WS channel to the client.
    const usePermissionBridge = permissionMode !== "bypassPermissions" && !!this.onPermissionRequest;
    const canUseTool = usePermissionBridge
      ? async (
          toolName: string,
          input: Record<string, unknown>,
          options: { signal: AbortSignal; suggestions?: unknown[]; blockedPath?: string; decisionReason?: string; toolUseID: string; agentID?: string },
        ) => {
          const requestId = generateUUID7();
          const sessionId = this.sdkSessionId ?? this.id;

          try {
            // Emit the permission request through the sidecar WS channel
            this.onPermissionRequest!({
              requestId,
              sessionId,
              toolName,
              input,
              toolUseId: options.toolUseID,
              suggestions: options.suggestions as Record<string, unknown>[] | undefined,
              blockedPath: options.blockedPath,
              requestReason: options.decisionReason,
              agentId: options.agentID,
              timestamp: new Date().toISOString(),
            });

            // Race abort signal against pending response
            const response = await new Promise<PermissionResponse>((resolve, reject) => {
              const onAbort = () => reject(new Error("canUseTool aborted"));
              if (options.signal.aborted) {
                onAbort();
                return;
              }
              options.signal.addEventListener("abort", onAbort, { once: true });
              this.pendingPermissions.waitFor(requestId).then(
                (res) => {
                  options.signal.removeEventListener("abort", onAbort);
                  resolve(res);
                },
                (err) => {
                  options.signal.removeEventListener("abort", onAbort);
                  reject(err);
                },
              );
            });

            // Map to SDK PermissionResult
            if (response.result.behavior === "allow") {
              return {
                behavior: "allow" as const,
                updatedInput: response.result.updatedInput,
                updatedPermissions: response.result.updatedPermissions as any,
                toolUseID: options.toolUseID,
              };
            } else {
              return {
                behavior: "deny" as const,
                message: response.result.message,
                interrupt: response.result.interrupt,
                toolUseID: options.toolUseID,
              };
            }
          } catch {
            return {
              behavior: "deny" as const,
              message: "Permission request cancelled",
              toolUseID: options.toolUseID,
            };
          }
        }
      : undefined;

    const sdkOptions: CCOptions = {
      cwd: this.config.cwd,
      model: this.config.model || "claude-sonnet-4-20250514",
      maxTurns: this.config.maxTurns || 100,
      permissionMode,
      systemPrompt: this.config.appendSystemPrompt
        ? { type: "preset" as const, preset: "claude_code" as const, append: this.config.appendSystemPrompt }
        : undefined,
      allowDangerouslySkipPermissions: permissionMode === "bypassPermissions",
      maxThinkingTokens: this.config.maxThinkingTokens,
      includePartialMessages: this.config.includePartialMessages ?? true,
      resume: this.config.resume
        ? (this.config.resumeAgentSessionAt ?? this.sdkSessionId ?? this.id)
        : undefined,
      ...(process.env.CLAUDE_CODE_PATH && { pathToClaudeCodeExecutable: process.env.CLAUDE_CODE_PATH }),
      executable: "node",
      env: {
        ...process.env,
        ANTHROPIC_API_KEY: apiKey,
        ...(baseUrl && { ANTHROPIC_BASE_URL: baseUrl }),
      },
      stderr: (data: string) => {
        this.logger.debug({ sessionId: this.id, stderr: data.trim() }, "CLI stderr");
      },
      ...(Object.keys(mcpServers).length > 0 && { mcpServers }),
      ...(canUseTool && { canUseTool }),
      ...(this.onHookEvent && this.config.hooks && this.config.hooks.length > 0 && {
        hooks: buildHooks(
          () => this.sdkSessionId ?? this.id,
          this.onHookEvent,
          this.pendingHooks,
          this.logger,
          this.config.hooks,
        ),
      }),
    };

    this.queryInstance = query({
      prompt: this.promptQueue,
      options: sdkOptions,
    });

    // Start background event consumer (runs for session lifetime)
    this.consumeEvents().catch((err) => {
      this.logger.error({ sessionId: this.id, err }, "Unexpected consumeEvents error");
    });

    this.state = "idle";
    this.resetIdleTimer();

    const mcpServerNames = Object.keys(mcpServers);
    this.logger.info(
      { sessionId: this.id, model: this.config.model, mcpServers: mcpServerNames },
      "Generator session started",
    );
  }

  // ── Send Message ──

  async sendMessage(prompt: string): Promise<EventTap> {
    // Wait for idle — session may be starting, busy, or terminated
    while (this.state !== "idle") {
      if (this.state === "terminated") {
        throw new SessionTerminatedError();
      }
      this.logger.info(
        { sessionId: this.id, state: this.state },
        "Waiting for session to become idle",
      );
      await this.waitForIdle();
    }

    this.clearIdleTimer();
    this.state = "busy";

    // Create a tap for this request
    const tapQueue = new AsyncQueue<TapEvent>();
    this.taps.add(tapQueue);

    // Push message into SDK's prompt input
    this.promptQueue.push({
      type: "user",
      message: { role: "user", content: prompt },
      parent_tool_use_id: null,
      session_id: this.sdkSessionId ?? this.id,
    });

    this.logger.info({ sessionId: this.id }, "Message sent to generator");

    return {
      events: tapQueue[Symbol.asyncIterator](),
      detach: () => {
        this.taps.delete(tapQueue);
        tapQueue.close();
      },
    };
  }

  // ── Control ──

  async interruptTurn(): Promise<void> {
    if (this.state !== "busy" || !this.queryInstance) return;

    this.logger.info({ sessionId: this.id }, "Interrupting current turn");

    try {
      await Promise.race([
        this.queryInstance.interrupt(),
        new Promise<never>((_, reject) =>
          setTimeout(() => reject(new Error("Interrupt timeout")), 2000),
        ),
      ]);
    } catch (err) {
      this.logger.warn({ sessionId: this.id, err }, "Interrupt failed, continuing");
    }
  }

  async terminate(): Promise<void> {
    if (this.state === "terminated") return;

    this.logger.info({ sessionId: this.id }, "Terminating generator session");

    this.clearIdleTimer();
    this.state = "terminated";

    this.promptQueue.close();
    this.pendingQuestions.rejectAll();
    this.pendingPermissions.rejectAll();
    this.pendingHooks.rejectAll();

    for (const tap of this.taps) {
      tap.close();
    }
    this.taps.clear();

    for (const waiter of this.idleWaiters) {
      waiter();
    }
    this.idleWaiters.length = 0;

    this.onTerminated?.();
  }

  // ── Background Event Loop ──

  private async consumeEvents(): Promise<void> {
    try {
      for await (const event of this.queryInstance!) {
        const sdkEvent = event as Record<string, unknown>;

        // Capture SDK session ID from init event
        if (
          sdkEvent.type === "system" &&
          sdkEvent.subtype === "init" &&
          sdkEvent.session_id
        ) {
          this.sdkSessionId = sdkEvent.session_id as string;
          this.logger.info(
            { sessionId: this.id, sdkSessionId: this.sdkSessionId },
            "SDK session ID captured",
          );
        }

        // Passthrough: broadcast raw SDK event directly to taps
        for (const tap of this.taps) {
          try {
            tap.push(sdkEvent);
          } catch {
            // Tap already closed
          }
        }

        // Turn boundary: 'result' event means SDK finished this turn
        if (sdkEvent.type === "result") {
          this.logger.info(
            {
              sessionId: this.id,
              subtype: sdkEvent.subtype,
              isError: sdkEvent.is_error,
              numTurns: sdkEvent.num_turns,
              errors: (sdkEvent as Record<string, unknown>).errors,
            },
            "SDK result event received",
          );
          this.onTurnComplete();
        }
      }
    } catch (err) {
      this.logger.error(
        {
          sessionId: this.id,
          errorType: typeof err,
          errorName: err instanceof Error ? err.name : undefined,
          errorMessage: err instanceof Error ? err.message : String(err),
          errorConstructor: (err as any)?.constructor?.name,
          errorStack: err instanceof Error ? err.stack?.split("\n").slice(0, 5).join("\n") : undefined,
        },
        "SDK event consumption error",
      );

      const errorEvent: AgentEvent = {
        type: "system",
        subtype: "error",
        error: err instanceof Error ? err.message : String(err),
      };
      for (const tap of this.taps) {
        try {
          tap.push(errorEvent);
        } catch {
          // Tap closed
        }
      }
    } finally {
      await this.terminate();
    }
  }

  private onTurnComplete(): void {
    this.logger.info({ sessionId: this.id }, "Turn completed");
    this.state = "idle";

    for (const tap of this.taps) {
      tap.close();
    }
    this.taps.clear();

    this.resetIdleTimer();

    const next = this.idleWaiters.shift();
    if (next) next();
  }

  private waitForIdle(timeoutMs = 60_000): Promise<void> {
    return new Promise<void>((resolve, reject) => {
      if (this.state === "idle") {
        resolve();
        return;
      }
      if (this.state === "terminated") {
        reject(new Error("Session terminated while waiting for idle"));
        return;
      }

      const timer = setTimeout(() => {
        const idx = this.idleWaiters.indexOf(onIdle);
        if (idx >= 0) this.idleWaiters.splice(idx, 1);
        reject(new Error("Timeout waiting for session to become idle"));
      }, timeoutMs);

      const onIdle = () => {
        clearTimeout(timer);
        resolve();
      };
      this.idleWaiters.push(onIdle);
    });
  }

  // ── Idle Timeout ──

  private resetIdleTimer(): void {
    this.clearIdleTimer();
    if (this.idleTimeoutMs > 0) {
      this.idleTimer = setTimeout(() => {
        this.logger.info({ sessionId: this.id }, "Idle timeout reached, terminating");
        this.terminate().catch((err) => {
          this.logger.error({ sessionId: this.id, err }, "Error during idle timeout termination");
        });
      }, this.idleTimeoutMs);
      if (this.idleTimer.unref) this.idleTimer.unref();
    }
  }

  private clearIdleTimer(): void {
    if (this.idleTimer) {
      clearTimeout(this.idleTimer);
      this.idleTimer = null;
    }
  }
}

