import type { Part, TokenUsage, FinishReason } from "@deus-hq/api";

export interface StreamContext {
  sessionId: string;
  messageId: string;
}

export interface EventTransformer<TEvent> {
  /** Process a single event → new or updated parts */
  process(event: TEvent): Part[];
  /** Finalize the stream — flush any buffered state */
  finish(): { parts: Part[]; usage: TokenUsage; cost?: number; finishReason?: FinishReason };
  /** Get all parts accumulated so far */
