import { SessionChannelEventSchema, type AgentStatus } from "@agnt/shared";
import type { Part, TokenUsage, FinishReason, WebSocketEvent } from "@deus-hq/api";
import { partToEntityInput } from "../messages/transforms.js";
import type { DODb } from "../db/do.js";
import type { Log } from "../log.js";
import {
  insertMessage,
  updateMessage,
  insertPart,
  updatePart,
  appendEvent,
  getParts,
} from "./sql.js";
import { createTransformPipeline, type TransformPipeline } from "./transform-pipeline.js";
import type { AgentSessionState } from "./types.js";
import { parseWsMessage } from "../do-shared/index.js";

// ---------------------------------------------------------------------------
// Host interface — AgentSession implements this, passes `this` directly
// ---------------------------------------------------------------------------

export interface TurnHost {
  readonly db: DODb;
  readonly state: AgentSessionState;
  readonly log: Log;
  pipeline: TransformPipeline | null;
  persistedPartIds: Set<string>;
  saveState(): void;
  broadcastToClients(event: WebSocketEvent): void;
  scheduleAlarm(context: { type: "db_flush"; attempt: number }, delayMs: number): void;
  triggerSnapshot(): void;
}

/** Postgres flush delay after turn end (ms) */
const DB_FLUSH_DELAY_MS = 2_000;

// ---------------------------------------------------------------------------
// Sidecar message dispatch
// ---------------------------------------------------------------------------

export function handleSidecarMessage(ctx: TurnHost, message: string | ArrayBuffer): void {
  const result = parseWsMessage(message, SessionChannelEventSchema, "agent-session");
  if (!result.ok) return;

  const event = result.data;

  switch (event.event) {
    case "agent:output":
      handleAgentOutput(ctx, event.data);
      break;

    case "agent:status":
      ctx.log.info("agent status", { ...event.data });
      handleAgentStatus(ctx, event.data.status, event.data.error);
      break;

    case "mcp:question":
      // Forward MCP questions to client WebSockets
      ctx.broadcastToClients({
        type: "mcp.question",
        data: event.data,
      });
      break;

    case "permission:request":
      // Forward permission requests (canUseTool bridge) to client WebSockets
      ctx.broadcastToClients({
        type: "permission.request",
        data: event.data,
      });
      break;

    case "hook:request":
      // Forward hook events to client WebSockets.
      // Decision hooks use "hook.request" (agent blocked, needs response);
      // observe-only hooks use "hook.event" (fire-and-forget).
      ctx.broadcastToClients({
        type: event.data.needsResponse ? "hook.request" : "hook.event",
        data: event.data,
      } as WebSocketEvent);
      break;
  }
}

// ---------------------------------------------------------------------------
// Agent output processing (hot path)
// ---------------------------------------------------------------------------

function handleAgentOutput(
  ctx: TurnHost,
  output: { sessionId: string; timestamp: string; data: Record<string, unknown> },
): void {
  if (!ctx.state.sessionId) return;

  const rawEvent = output.data;

  // Capture agent session ID from system/init (first event of each SDK query)
  if (
    rawEvent.type === "system" &&
    rawEvent.subtype === "init" &&
    typeof rawEvent.session_id === "string"
  ) {
    ctx.state.agentSessionId = rawEvent.session_id;
    ctx.saveState();
  }

  // Emit session.compacting on status change (START signal, before compact_boundary)
  if (rawEvent.type === "system" && rawEvent.subtype === "status" && rawEvent.status === "compacting") {
    ctx.broadcastToClients({
      type: "session.compacting",
      sessionId: ctx.state.sessionId!,
    } as WebSocketEvent);
  }

  // Ensure pipeline exists for this turn
  if (!ctx.pipeline) {
    if (ctx.state.currentMessageId && ctx.state.status === "running") {
      // Resuming after hibernation — rebuild pipeline, don't create new message
      rebuildPipeline(ctx);
    } else {
      startTurn(ctx);
    }
  }

  // Run through transform pipeline
  const newOrUpdatedParts = ctx.pipeline!.processEvent(output.data);

  // Persist to DO SQLite (synchronous, write coalescing = atomic)
  for (const part of newOrUpdatedParts) {
    const entityInput = partToEntityInput(part, getPartIndex(ctx, part));

    if (ctx.persistedPartIds.has(part.id)) {
      // Update existing part
      updatePart(ctx.db, part.id, entityInput.data);
    } else {
      // Insert new part
      insertPart(ctx.db, {
        id: entityInput.id,
        messageId: entityInput.messageId,
        sessionId: entityInput.sessionId,
        type: entityInput.type,
        index: entityInput.index,
        data: entityInput.data,
      });
      ctx.persistedPartIds.add(part.id);
    }
  }

  // Append raw event to replay log
  appendEvent(ctx.db, ctx.state.sessionId, "agent:output", output);

  // Broadcast lifecycle events to client WebSockets
  for (const part of newOrUpdatedParts) {
    ctx.broadcastToClients({
      type: "message.part",
      sessionId: ctx.state.sessionId,
      messageId: ctx.state.currentMessageId!,
      part,
    } as WebSocketEvent);
  }
}

// ---------------------------------------------------------------------------
// Agent status changes
// ---------------------------------------------------------------------------

function handleAgentStatus(
  ctx: TurnHost,
  sidecarStatus: AgentStatus,
  error?: string,
): void {
  // Map sidecar agent statuses to DO states (aligned with public SessionStatus)
  const doStatus =
    sidecarStatus === "running" ? "running" as const :
    sidecarStatus === "failed" ? "error" as const :
    "ready" as const; // idle + completed → ready

  ctx.state.status = doStatus;

  let result: { finalized: boolean; usage?: TokenUsage; cost?: number; finishReason?: FinishReason } = { finalized: false };
  if (sidecarStatus === "completed" || sidecarStatus === "failed") {
    result = finalizeTurn(ctx);
  }

  // Broadcast turn.ended before clearing IDs (we need the turnId for the event).
  if (result.finalized && ctx.state.currentTurnId) {
    ctx.broadcastToClients({
      type: "turn.ended",
      sessionId: ctx.state.sessionId!,
      turnId: ctx.state.currentTurnId,
      tokens: result.usage,
      cost: result.cost,
      ...(result.finishReason && { finishReason: result.finishReason }),
      ...(error && { error }),
    } as WebSocketEvent);
  }

  // Clear turn-scoped IDs so persisted state is clean after DO eviction.
  if (result.finalized) {
    ctx.state.currentTurnId = null;
    ctx.state.currentMessageId = null;
  }

  ctx.saveState();

  // Fire-and-forget snapshot after turn completion (both success and failure)
  if (result.finalized && ctx.state.environmentId) {
    ctx.triggerSnapshot();
  }
}

// ---------------------------------------------------------------------------
// Turn start / rebuild / finalize
// ---------------------------------------------------------------------------

export function startTurn(ctx: TurnHost): void {
  const messageId = crypto.randomUUID();
  // Reuse the turnId that postMessage already set, or generate a new one
  // if startTurn is called without a preceding postMessage (e.g., sidecar-initiated).
  const turnId = ctx.state.currentTurnId || crypto.randomUUID();

  ctx.state.currentMessageId = messageId;
  ctx.state.currentTurnId = turnId;
  ctx.state.status = "running";
  // Agent acknowledged — the execute command was delivered successfully.
  // Clear the safety-net pendingExecute so webSocketClose() doesn't
  // trigger spurious recovery if the WS drops mid-turn.
  ctx.state.pendingExecute = null;
  ctx.saveState();

  // Create the message row in DO SQLite
  insertMessage(ctx.db, {
    id: messageId,
    sessionId: ctx.state.sessionId!,
    role: "ASSISTANT",
    turnId,
  });

  // Create transform pipeline for this turn
  ctx.pipeline = createTransformPipeline(ctx.state.agentType, {
    sessionId: ctx.state.sessionId!,
    messageId,
  });

  ctx.persistedPartIds.clear();

  // Broadcast turn start
  ctx.broadcastToClients({
    type: "turn.started",
    sessionId: ctx.state.sessionId!,
    turnId,
    messageId,
  } as WebSocketEvent);
}

function rebuildPipeline(ctx: TurnHost): void {
  ctx.pipeline = createTransformPipeline(ctx.state.agentType, {
    sessionId: ctx.state.sessionId!,
    messageId: ctx.state.currentMessageId!,
  });

  // Rebuild persistedPartIds from DO SQLite so we don't duplicate inserts
  const existingParts = getParts(ctx.db, [ctx.state.currentMessageId!]);
  ctx.persistedPartIds.clear();
  for (const part of existingParts) {
    ctx.persistedPartIds.add(part.id);
  }

  ctx.log.info("rebuilt pipeline after hibernation", { messageId: ctx.state.currentMessageId, parts: existingParts.length });
}

export function finalizeTurn(ctx: TurnHost): { finalized: boolean; usage?: TokenUsage; cost?: number; finishReason?: FinishReason } {
  if (!ctx.pipeline) return { finalized: false };

  const { usage, cost, finishReason } = ctx.pipeline.finish();

  // Update message with completion metadata
  if (ctx.state.currentMessageId) {
    updateMessage(ctx.db, ctx.state.currentMessageId, {
      completedAt: new Date().toISOString(),
      metadata: {
        tokens: usage,
        cost,
        finishReason,
      },
    });
  }

  // Broadcast message ended
  ctx.broadcastToClients({
    type: "message.ended",
    sessionId: ctx.state.sessionId!,
    messageId: ctx.state.currentMessageId!,
    tokens: usage,
    cost,
    ...(finishReason && { finishReason }),
  } as WebSocketEvent);

  ctx.pipeline = null;

  // Session WS stays open for subsequent turns (persistent connection)

  // Schedule Postgres flush
  ctx.scheduleAlarm({ type: "db_flush", attempt: 0 }, DB_FLUSH_DELAY_MS);

  return { finalized: true, usage, cost, finishReason };
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function getPartIndex(ctx: TurnHost, part: Part): number {
  if (!ctx.pipeline) return 0;
  const allParts = ctx.pipeline.getParts();
  const idx = allParts.findIndex((p) => p.id === part.id);
  return idx >= 0 ? idx : allParts.length;
}

