import { z } from "zod";
import { McpServersSchema } from "./mcp.js";
import { HookEventNameSchema } from "./hook.js";

export const AgentStatusSchema = z.enum(["idle", "running", "completed", "failed"]);
export type AgentStatus = z.infer<typeof AgentStatusSchema>;

export const AgentSessionSchema = z.object({
  id: z.string().min(1),
  sandboxId: z.string().min(1),
  model: z.string().default("claude-sonnet-4-20250514"),
  status: AgentStatusSchema,
  createdAt: z.string().datetime(),
});

export type AgentSession = z.infer<typeof AgentSessionSchema>;

// Structured payload for agent execution
export const AgentExecuteOptionsSchema = z.object({
  cwd: z.string().default("/home/user"),
  model: z.string().default("claude-sonnet-4-20250514"),
  permissionMode: z.enum(["default", "plan", "bypassPermissions"]).default("bypassPermissions"),
  maxTurns: z.number().int().positive().optional(),
  apiKey: z.string().optional(),
  resume: z.boolean().optional(),
  resumeAgentSessionAt: z.string().optional(),
  appendSystemPrompt: z.string().optional(),
  mcpServers: McpServersSchema.optional(),
  baseUrl: z.string().url().optional(),
  maxThinkingTokens: z.number().int().positive().optional(),
  includePartialMessages: z.boolean().optional(),
  shouldResetGenerator: z.boolean().optional(),
  /** Hook events to subscribe to. Only listed hooks are registered on the agent.
   *  Omit or pass empty array for zero hook overhead (default). */
  hooks: z.array(HookEventNameSchema).optional(),
});

export type AgentExecuteOptions = z.infer<typeof AgentExecuteOptionsSchema>;

export const AgentExecutePayloadSchema = z.object({
  sessionId: z.string().min(1),
  prompt: z.string().min(1),
  options: AgentExecuteOptionsSchema.default({}),
});

export type AgentExecutePayload = z.infer<typeof AgentExecutePayloadSchema>;

export const AgentCancelPayloadSchema = z.object({
  sessionId: z.string().min(1),
});

export type AgentCancelPayload = z.infer<typeof AgentCancelPayloadSchema>;

// Discriminated union for agent commands
export const AgentCommandSchema = z.discriminatedUnion("type", [
  z.object({
    type: z.literal("execute"),
    payload: AgentExecutePayloadSchema,
  }),
  z.object({
    type: z.literal("cancel"),
    payload: AgentCancelPayloadSchema,
  }),
]);

export type AgentCommand = z.infer<typeof AgentCommandSchema>;

// Agent output — raw SDK event passthrough envelope.
// The sidecar forwards raw agent SDK events untransformed in `data`.
// The backend adapter layer interprets agent-specific event shapes.
// Using passthrough() to enforce object structure while preserving all fields.
export const AgentOutputSchema = z.object({
  sessionId: z.string().min(1),
  timestamp: z.string().datetime(),
  data: z.object({
    type: z.string().optional(),
    subtype: z.string().optional(),
  }).passthrough(),
});

export type AgentOutput = z.infer<typeof AgentOutputSchema>;

