import { z } from "zod";
import { AgentOutputSchema, AgentExecutePayloadSchema, AgentStatusSchema } from "./agent.js";
import { McpQuestionSchema, McpAnswerSchema } from "./mcp.js";
import { PermissionRequestSchema, PermissionResponseSchema } from "./permission.js";
import { HookRequestSchema, HookResponseSchema } from "./hook.js";

// ---------------------------------------------------------------------------
// Session Channel: AgentSession DO ↔ Sidecar
// One WebSocket per session. Carries session-specific agent events and commands.
// ---------------------------------------------------------------------------

// ── Events: Sidecar → AgentSession DO ──

export const SessionChannelEventSchema = z.discriminatedUnion("event", [
  z.object({
    event: z.literal("agent:output"),
    data: AgentOutputSchema,
  }),
  z.object({
    event: z.literal("agent:status"),
    data: z.object({
      sessionId: z.string().min(1),
      status: AgentStatusSchema,
      error: z.string().optional(),
    }),
  }),
  z.object({
    event: z.literal("mcp:question"),
    data: McpQuestionSchema,
  }),
  z.object({
    event: z.literal("permission:request"),
    data: PermissionRequestSchema,
  }),
  z.object({
    event: z.literal("hook:request"),
    data: HookRequestSchema,
  }),
]);

export type SessionChannelEvent = z.infer<typeof SessionChannelEventSchema>;

// ── Commands: AgentSession DO → Sidecar ──

export const SessionChannelCommandSchema = z.discriminatedUnion("command", [
  z.object({
    command: z.literal("agent:execute"),
    data: AgentExecutePayloadSchema,
  }),
  z.object({
    command: z.literal("agent:cancel"),
    data: z.object({ sessionId: z.string().min(1) }),
  }),
  z.object({
    command: z.literal("mcp:answer"),
    data: McpAnswerSchema,
  }),
  z.object({
    command: z.literal("permission:response"),
    data: PermissionResponseSchema,
  }),
  z.object({
    command: z.literal("hook:response"),
    data: HookResponseSchema,
  }),
]);

export type SessionChannelCommand = z.infer<typeof SessionChannelCommandSchema>;

