import { DurableObject } from "cloudflare:workers";
import { SessionChannelCommandSchema, type SessionChannelCommand } from "@agnt/shared";
import type { Env } from "../types.js";
import type { Message, UserMessage, WebSocketEvent, SessionEvent } from "@deus-hq/api";
import { createLog, type Log } from "../log.js";
import { generateUUID7 } from "../utils/uuid7.js";
import { createDODb, type DODb } from "../db/do.js";
import { createDb, getConnectionString } from "../db/pg.js";
import {
  migrateAgentSessionSql,
  getState,
  setState,
  insertMessage,
  insertPart,
  appendEvent as appendEventSql,
  getEvents,
  getSessionMessages,
} from "./sql.js";
import type { TransformPipeline } from "./transform-pipeline.js";
import { flushToDb, getRetryDelay } from "./pg-sync.js";
import type { AgentSessionState } from "./types.js";
import { DEFAULT_AGENT_SESSION_STATE } from "./types.js";
import { handleSidecarMessage, finalizeTurn, type TurnHost } from "./turn-lifecycle.js";
import { handleClientMessage } from "./client-handler.js";
import type { EnvironmentEvent } from "../environment/do/events.js";
import { handleEnvironmentEvent, type EnvironmentEventHost } from "./environment-handlers.js";
import {
  validateSidecarJwt,
  replaceAndAcceptWebSocket,
  sendToTagged,
  sendToTaggedExcept,
} from "../do-shared/index.js";
import type { AgentSessionRpc } from "../do-rpc.js";

/** Idle session TTL before cleanup (ms) */
const IDLE_TTL_MS = 30 * 60_000; // 30 minutes

// Alarm context keys stored in DO SQL state table
const ALARM_CONTEXT_KEY = "alarm_context";

type AlarmContext =
  | { type: "db_flush"; attempt: number }
  | { type: "idle_cleanup" };

export class AgentSession extends DurableObject<Env> implements TurnHost, EnvironmentEventHost, AgentSessionRpc {
  db: DODb;
  state: AgentSessionState = { ...DEFAULT_AGENT_SESSION_STATE };
  pipeline: TransformPipeline | null = null;
  persistedPartIds = new Set<string>();
  log: Log = createLog("agent-session");

  constructor(ctx: DurableObjectState, env: Env) {
    super(ctx, env);
    this.db = createDODb(ctx.storage);
    // Run migration + state load synchronously in constructor.
    // DO SQLite exec is sync; blockConcurrencyWhile defers requests until constructor finishes.
    migrateAgentSessionSql(this.db);
    this.loadState();
    if (this.state.sessionId) {
      this.log = this.log.child({ sessionId: this.state.sessionId, environmentId: this.state.environmentId });
    }
  }

  private loadState(): void {
    const raw = getState(this.db, "session_state");
    if (raw) {
      this.state = { ...DEFAULT_AGENT_SESSION_STATE, ...JSON.parse(raw) };
    }
  }

  saveState(): void {
    setState(this.db, "session_state", JSON.stringify(this.state));
  }

  // ---------------------------------------------------------------------------
  // RPC methods (called by routes, Environment DO)
  // ---------------------------------------------------------------------------

  /** Initialize a new session */
  async initialize(params: {
    sessionId: string;
    organizationId: string;
    environmentId: string;
    agentType?: "claude-code" | "codex";
  }): Promise<void> {
    this.state = {
      ...DEFAULT_AGENT_SESSION_STATE,
      sessionId: params.sessionId,
      organizationId: params.organizationId,
      environmentId: params.environmentId,
      agentType: params.agentType ?? "claude-code",
    };
    this.log = this.log.child({ sessionId: params.sessionId, environmentId: params.environmentId });
    this.saveState();
  }

  /** Post a user message and trigger agent execution via sidecar WS */
  async postMessage(prompt: string, options?: Record<string, unknown>): Promise<{ messageId: string; message: UserMessage }> {
    if (!this.state.sessionId) {
      throw new Error("Session not initialized");
    }

    if (this.state.status === "running") {
      throw new Error("A turn is already in progress");
    }

    if (this.state.pendingExecute) {
      throw new Error("A pending execute is already awaiting sidecar connection");
    }

    // Create user message in DO SQLite.
    // Generate the turnId here so the assistant response (created later in startTurn)
    // shares the same turnId — enabling turn-based message grouping.
    const messageId = generateUUID7();
    const turnId = generateUUID7();

    this.state.currentTurnId = turnId;
    this.saveState();

    insertMessage(this.db, {
      id: messageId,
      sessionId: this.state.sessionId,
      role: "USER",
      turnId,
    });

    // Persist user prompt as a TEXT part so history includes user messages
    const partId = generateUUID7();
    insertPart(this.db, {
      id: partId,
      messageId: messageId,
      sessionId: this.state.sessionId,
      type: "TEXT",
      index: 0,
      data: { text: prompt },
    });

    // Construct the user message for return (used by client-handler to broadcast)
    const userMessage: UserMessage = {
      id: messageId,
      sessionId: this.state.sessionId,
      role: "USER",
      turnId,
      parts: [{
        id: partId,
        sessionId: this.state.sessionId,
        messageId,
        type: "TEXT",
        text: prompt,
        state: "DONE",
      }],
      createdAt: new Date().toISOString(),
    };

    // Always pass agentSessionId — the sidecar decides whether to resume.
    let mergedOptions = options ?? {};
    if (this.state.agentSessionId) {
      mergedOptions = {
        ...mergedOptions,
        resume: true,
        resumeAgentSessionAt: this.state.agentSessionId,
      };
    }

    // Build the execute command (validated per CLAUDE.md constraint)
    const cmd = SessionChannelCommandSchema.safeParse({
      command: "agent:execute",
      data: {
        sessionId: this.state.sessionId,
        prompt,
        options: mergedOptions,
      },
    });
    if (!cmd.success) {
      throw new Error(`Invalid execute command: ${JSON.stringify(cmd.error.issues)}`);
    }

    // Always persist pendingExecute as a safety net before attempting delivery.
    // Cleared when the agent actually acknowledges (startTurn on first output).
    // This guards against stale sidecar WS: if the sandbox died but the WS close
    // event hasn't arrived yet, sendToSidecar() silently fails into a dead socket.
    // When the close event lands, webSocketClose() sees pendingExecute and triggers recovery.
    this.state.pendingExecute = {
      sessionId: this.state.sessionId,
      prompt,
      options: mergedOptions,
    };
    this.saveState();

    const sidecarSockets = this.ctx.getWebSockets("sidecar");
    if (sidecarSockets.length > 0) {
      // Sidecar WS appears open — send execute directly.
      // If the WS is stale (sandbox dead), the message is lost but pendingExecute
      // persists. webSocketClose() will trigger recovery when the close event arrives.
      this.sendToSidecar(cmd.data);
    } else {
      // No sidecar WS — ask Environment DO to establish the connection.
      // It will POST /connect-session (running) or reprovision (dead).
      // pendingExecute is consumed in handleSidecarUpgrade() when the new WS lands.
      const envStub = this.env.ENVIRONMENT.getByName(this.state.environmentId!);

