import { ClientCommandSchema, type ClientCommand, type WebSocketEvent } from "@deus-hq/api";
import type { SessionChannelCommand } from "@agnt/shared";
import type { AgentSession } from "./agent-session.js";
import { parseWsMessage } from "../do-shared/index.js";

/**
 * Parse and dispatch client WebSocket messages.
 *
 * Thin validation layer — delegates actual work to DO methods
 * (`postMessage`, `sendToSidecar`).
 */
export function handleClientMessage(session: AgentSession, ws: WebSocket, message: string | ArrayBuffer): void {
  const result = parseWsMessage(message, ClientCommandSchema, "agent-session");
  if (!result.ok) return;

  handleClientCommand(session, ws, result.data);
}

function handleClientCommand(session: AgentSession, ws: WebSocket, command: ClientCommand): void {
  switch (command.type) {
    case "message.send":
      session.postMessage(command.text, command.options)
        .then(({ message }) => {
          // Broadcast user message to other connected clients (not the sender —
          // the sender already applied it optimistically via session-client send()).
          session.broadcastToOtherClients({
            type: "message.started",
            message,
          } as WebSocketEvent, ws);
        })
        .catch((err) => {
          ws.send(JSON.stringify({
            type: "error",
            code: "MESSAGE_SEND_FAILED",
            message: err instanceof Error ? err.message : String(err),
          }));
        });
      break;

    case "agent.cancel":
      session.sendToSidecar({
        command: "agent:cancel",
        data: { sessionId: session.state.sessionId! },
      } as SessionChannelCommand);
      break;

    case "mcp.answer":
      session.sendToSidecar({
        command: "mcp:answer",
        data: {
          ...command.data,
          sessionId: session.state.sessionId!,
        },
      } as SessionChannelCommand);
      break;

    case "permission.response":
      session.sendToSidecar({
        command: "permission:response",
        data: {
          ...command.data,
          sessionId: session.state.sessionId!,
        },
      } as SessionChannelCommand);
      break;

    case "hook.response":
      session.sendToSidecar({
        command: "hook:response",
        data: {
          ...command.data,
          sessionId: session.state.sessionId!,
        },
      } as SessionChannelCommand);
      break;
  }
}

