import { z } from "zod";

export const SandboxConfigSchema = z.object({
  id: z.string().uuid(),
  image: z.string().min(1),
  cpuLimit: z.number().min(0.5).max(8).default(1),
  memoryLimitMb: z.number().min(256).max(16384).default(2048),
  timeoutSeconds: z.number().min(30).max(3600).default(300),
  networkPolicy: z.enum(["none", "restricted", "full"]).default("restricted"),
});

export type SandboxConfig = z.infer<typeof SandboxConfigSchema>;

// Runtime status of a sandbox VM (used internally by sidecar)
export const SandboxRuntimeStatusSchema = z.enum([
  "creating",
  "running",
  "stopping",
  "stopped",
  "error",
]);

export type SandboxRuntimeStatus = z.infer<typeof SandboxRuntimeStatusSchema>;

export const SandboxStateSchema = z.object({
  id: z.string().uuid(),
  status: SandboxRuntimeStatusSchema,
  config: SandboxConfigSchema,
  startedAt: z.string().datetime().optional(),
  stoppedAt: z.string().datetime().optional(),
});

export type SandboxState = z.infer<typeof SandboxStateSchema>;

